import{_ as e,c as a,o as c,a as t}from"./app.09cc872b.js";const u=JSON.parse('{"title":"freplace Design","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/architecture/freplace.md","lastUpdated":1782412920000}'),i={name:"openshield-xdp/architecture/freplace.md"},o=t('<h1 id="freplace-design" tabindex="-1">freplace Design <a class="header-anchor" href="#freplace-design" aria-hidden="true">#</a></h1><p>Individual pipeline stages in <code>ebpf/modules/</code> can compile as standalone <code>freplace</code> programs:</p><ul><li><code>ban_check</code> \u2014 replace ban lookup path</li><li><code>rate_limit</code> \u2014 replace rate threshold path</li><li><code>conn_track</code> \u2014 replace connection tracking</li><li><code>dns_amp</code> \u2014 replace DNS amplification check</li><li><code>l7_filter</code> \u2014 replace L7 signature matching</li></ul><p><strong>Benefits</strong>: hot-patch individual stages without reloading main XDP, independent compilation, smaller verifier footprint.</p><p>Currently <code>#include</code>d directly. freplace loading via <code>cilium/ebpf.AttachFreplace</code> pending upstream kernel support (kernel \u2265 5.11, <code>CONFIG_DEBUG_INFO_BTF=y</code>).</p>',5),r=[o];function n(l,d,p,s,_,h){return c(),a("div",null,r)}const m=e(i,[["render",n]]);export{u as __pageData,m as default};
